  ('pukao-1fb53453-moex-00387', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '依行政程序法規定，關於行政命令訂定程序之敘述，下列何者錯誤？', '["法規命令草案之預告，除於政府公報或新聞紙公告，並未禁止以其他方式使大眾知悉草案內容", "任何人均得於指定期間內向指定機關陳述意見，惟利害關係人之意見陳述，訂定機關應舉行聽證予以 回應", "法規命令之發布，限於刊登在政府公報或新聞紙，在機關首頁登載並不符合生效要件", "解釋性規則及裁量基準，以發布為生效要件"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00388', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '下列何者非為行政機關之一般處分？', '["國民小學學區之劃分", "主管機關公告特定地區食品限制其輸入", "行人徒步區之劃設", "因禽流感命特定地區之養雞場進行雞隻之撲殺"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00389', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '水利法第19條之1規定：「水權人交換使用全部或一部分引水量者，應由雙方訂定換水契約，於報經 主管機關核准後生效。但交換使用時間超過三年者，應由雙方依法辦理變更登記。」下列敘述何者錯 誤？', '["水權人間之換水契約應屬私法契約", "該核准為形成私法效果之行政處分", "3年時間限制為核准處分規制內容", "該契約如有違法之瑕疵則核准無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00390', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '甲建管機關核發乙公司建照後，於乙施工期間，鄰人丙偶然發現該建照恐有違法瑕疵，下列敘述何者 正確？', '["丙向甲舉發違法後，甲應訴請法院撤銷該違法行政處分，但應考量乙之信賴利益", "甲應先命乙暫停施工，並靜待檢調機關調查有無違法後，始得依職權撤銷該建照", "於法定救濟期間經過後，丙仍得以利害關係人之身分，向甲申請撤銷該違法建照", "丙應先向行政法院申請假扣押乙之施工機具，以防甲藉由儘早完工試圖規避違法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00391', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '下列何者屬於已發生效力之行政處分？', '["對特定違規業者作成停止其營業之命令", "已經執行完畢之違章建築強制拆除行為", "應人民請求而公開之空氣污染調查報告", "未公告或刊登政府公報之書面一般處分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00392', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '下列何種情形，不適用公法上不當得利返還請求權？', '["甲公務員因溢領一次性退休金之給付，主管機關撤銷原核定處分後，命甲返還溢領金額", "乙繳付工業區開發管理基金後，因非可歸責於己之事由而未設廠，向主管機關請求返還", "丙之土地經徵收並領取補償金後，經查計算標準錯誤有溢領情形，補償機關請求丙返還", "丁廠商參與政府採購得標並已完工驗收，主管機關未給付工程尾款，丁訴請該機關返還"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
