  ('pukao-1fb53453-moex-00394', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '需用土地人申請徵收土地前，與土地所有人達成之協議價購，其法律性質為何？', '["行政契約", "行政處分", "私法契約", "事實行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00395', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '依最高行政法院實務見解，下列何者非屬觀念通知？', '["主管機關同意甫成立之公寓大廈管理委員會依法所為之報備", "公平交易委員會對檢舉人所為檢舉不成立之函文", "主管機關通知人民自行拆除違章建築之違章建築拆除通知單", "主管機關對人民團體選任職員簡歷冊之異動所為之核備"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00396', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '依據行政罰法與學理之見解，關於行政罰之敘述，下列何者正確？', '["為避免行政機關執法困擾，行政罰法得類推適用刑法共犯制度之規定", "個別法規有推定過失特別規定時，應優先於行政罰法責任條件之規定", "對同一違反義務行為，禁止同時科處行政罰並作成單純不利益行政處分", "對違反行政法上義務之行為，地方行政機關僅得依地方議會制定自治條例處罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL)
